            <textarea
              id="description"
              name="description"
              defaultValue={defaults?.description ?? ""}
            />
          </div>
        </div>
        <div className="panel stack">
          {includeStatus ? (
            <div className="field">
              <label htmlFor="status">Status</label>
              <select
                id="status"
                name="status"
                defaultValue={defaults?.status ?? IssueStatus.OPEN}
              >
                {issueStatuses.map((status) => (
                  <option key={status} value={status}>
                    {status}
                  </option>
                ))}
              </select>
            </div>
          ) : null}
          <div className="field">
            <label htmlFor="priority">Priority</label>
            <select
              id="priority"
              name="priority"
              defaultValue={defaults?.priority ?? IssuePriority.MEDIUM}
            >
