                <option key={priority} value={priority}>
                  {priority}
                </option>
              ))}
            </select>
          </div>
          <div className="field">
            <label htmlFor="dueDate">Due date</label>
            <input
              id="dueDate"
              name="dueDate"
              type="date"
              defaultValue={defaults?.dueDate ?? ""}
            />
          </div>
          <div className="field">
            <span>Labels</span>
            <div className="checkbox-list">
              {labels.map((label) => (
                <label key={label.id} className="checkbox-pill">
