import { notFound } from "next/navigation";

import {
  addCommentAction,
  deleteIssueAction,
  updateStatusAction,
} from "@/app/issues/actions";
import { formatDate } from "@/lib/utils";
import { getIssueById } from "@/server/issues";
import { issueStatuses } from "@/lib/constants";

type IssueDetailPageProps = {
  params: Promise<{ id: string }>;
};

export default async function IssueDetailPage({ params }: IssueDetailPageProps) {
  const { id } = await params;
  const issue = await getIssueById(id);

  if (!issue) {
    notFound();
  }

  const handleStatus = updateStatusAction.bind(null, issue.id);
  const handleDelete = deleteIssueAction.bind(null, issue.id);
  const handleComment = addCommentAction.bind(null, issue.id);

  return (
    <main className="page-shell">
      <div className="container stack">
        <div className="between">
          <div>
            <p className="muted">Issue detail</p>
            <h1>{issue.title}</h1>
          </div>
          <div className="actions">
            <Link className="button-link" href={`/issues/${issue.id}/edit`}>
              Edit
            </Link>
            <Link className="button-link" href="/issues">
              Back
            </Link>
          </div>
        </div>

        <div className="grid two">
          <section className="panel stack">
            <p>{issue.description || "No description provided."}</p>
            <div className="tag-row">
              <span className="tag status">{issue.status}</span>
              <span className="tag">{issue.priority}</span>
              {issue.issueLabels.map((entry) => (
                <span key={entry.labelId} className="tag">
                  {entry.label.name}
                </span>
              ))}
            </div>
            <div className="meta-list muted">
              <span>Due date: {formatDate(issue.dueDate)}</span>
              <span>Created: {formatDate(issue.createdAt)}</span>
              <span>Updated: {formatDate(issue.updatedAt)}</span>
            </div>
          </section>

          <aside className="stack">
            <form className="panel stack" action={handleStatus}>
              <div className="field">
                <label htmlFor="status">Status</label>
                <select id="status" name="status" defaultValue={issue.status}>
                  {issueStatuses.map((status) => (
                    <option key={status} value={status}>
                      {status}
                    </option>
                  ))}
                </select>
              </div>
              <button className="primary" type="submit">
                Update status
              </button>
